// ========================================================
// PARSE MESSAGE — Extrai dados do webhook Evolution API
// ========================================================
const body = $input.first().json.body || $input.first().json;

// Ignora mensagens enviadas por nós (fromMe)
if (body.data?.key?.fromMe === true) return [];

// Ignora eventos que não são mensagens
const event = body.event || '';
if (event && !event.includes('messages')) return [];

// Extrai instance name
const instance = body.instance || body.instanceName || '';

// Extrai número do remetente
const remoteJid = body.data?.key?.remoteJid || '';
const phone = remoteJid.replace('@s.whatsapp.net', '').replace('@g.us', '').replace(/\D/g, '');

// Ignora grupos
if (remoteJid.includes('@g.us')) return [];

// Extrai texto da mensagem
const message = body.data?.message;
let text = '';
if (message?.conversation) text = message.conversation;
else if (message?.extendedTextMessage?.text) text = message.extendedTextMessage.text;
else if (message?.imageMessage?.caption) text = message.imageMessage.caption;
else if (message?.videoMessage?.caption) text = message.videoMessage.caption;

const messageType = body.data?.messageType || 'conversation';
let media_type = null;
if (messageType === 'imageMessage') media_type = 'image';
else if (messageType === 'audioMessage') media_type = 'audio';
else if (messageType === 'videoMessage') media_type = 'video';
else if (messageType === 'documentMessage') media_type = 'document';

// Se não tem texto nem mídia, ignorar
if (!text && !media_type) return [];

return [{ json: { instance, phone, remoteJid, text: text || '[mídia recebida]', media_type, messageType, timestamp: new Date().toISOString() } }];

// Valida se encontrou usuário
const result = $('Find User').first().json;
const users = Array.isArray(result) ? result : [result];
const phone = $('Parse Message').first().json.phone;
const instance = $('Parse Message').first().json.instance;

if (!users.length || !users[0]?.user_id) {
  return [{ json: { error: true, message: 'Nenhum usuário para instância: ' + instance } }];
}
const user = users[0];
if (user.active === false) {
  return [{ json: { error: true, message: 'Usuário desativado' } }];
}
return [{ json: { error: false, user_id: user.user_id, display_name: user.display_name, evo_instance: user.evo_instance, phone, instance } }];

// Combina dados de subscription + lead + detecta tipo de agente
const subRaw = $('Get Subscription').first().json;
const leadRaw = $('Find or Create Lead').first().json;
const userData = $('Validate User').first().json;

const sub = Array.isArray(subRaw) ? subRaw[0] || {} : subRaw || {};
const lead = Array.isArray(leadRaw) ? leadRaw[0] || {} : leadRaw || {};

const stage = lead.stage || 'novo_contato';
const fluxo_id = lead.fluxo_id || '';
const objecoes_count = lead.objecoes_count || 0;

let agent_type = 'principal';
let agent_index = 0;
if ((stage === 'objecoes' || objecoes_count > 2) && sub.addon_objecao) {
  agent_type = 'objecao';
} else if (stage === 'prospecao' || (fluxo_id && fluxo_id.includes && fluxo_id.includes('prospec'))) {
  agent_type = 'prospec';
} else if (sub.agentes_extras > 0 && fluxo_id && fluxo_id.match && fluxo_id.match(/ae(\d)/)) {
  agent_type = 'extra';
  agent_index = parseInt(fluxo_id.match(/ae(\d)/)[1]);
}

return [{ json: {
  user_id: userData.user_id,
  lead_id: lead.lead_id,
  lead_nome: lead.nome,
  is_new_lead: lead.is_new || false,
  stage, agent_type, agent_index,
  evo_instance: userData.evo_instance,
  phone: userData.phone,
  sub_status: sub.status,
  creditos: sub.creditos_tokens || 0
} }];

// ========================================================
// BUILD PROMPT — Monta prompt + histórico + seleciona modelo
// ========================================================
const configRaw = $('Get Configs').first().json;
const configs = Array.isArray(configRaw) ? configRaw : [];
const configMap = {};
configs.forEach(item => { if (item.chave && item.valor !== undefined) configMap[item.chave] = item.valor; });

const agentData = $('Process Data').first().json;
const prefix = agentData.agent_type === 'principal' ? '' : agentData.agent_type === 'prospec' ? 'prospec_' : agentData.agent_type === 'objecao' ? 'ob_' : `ae${agentData.agent_index}_`;

function cfg(key, fb) { return configMap[`${prefix}${key}`] || configMap[key] || fb || ''; }

// PROMPT
let prompt = cfg('sistema_prompt', 'Você é um assistente de vendas profissional. Qualifique leads com base nos critérios definidos. Seja educado, persuasivo e objetivo.');
const objetivo = cfg('objetivo');
if (objetivo) prompt = `OBJETIVO: ${objetivo}\n\n${prompt}`;
const tonalidade = cfg('tonalidade');
if (tonalidade) prompt += `\n\nTONALIDADE: ${tonalidade}`;
const criterios = cfg('criterios_qualificacao');
if (criterios) prompt += `\n\nCRITÉRIOS DE QUALIFICAÇÃO:\n${criterios}`;
const instrucoes = cfg('instrucoes_comunicacao');
if (instrucoes) prompt += `\n\nINSTRUÇÕES DE COMUNICAÇÃO:\n${instrucoes}`;
prompt += '\n\nTAGS ESPECIAIS (use quando apropriado):';
prompt += '\n- [LEAD_QUALIFICADO] — quando o lead atende todos os critérios';
prompt += '\n- [LEAD_DESQUALIFICADO] — quando o lead não tem perfil';
prompt += '\n- [INICIAR_PAGAMENTO] — quando o lead quer pagar';
prompt += '\n\nIMPORTANTE: Mensagens curtas e naturais, como WhatsApp real. Máximo 3 parágrafos.';

// PROVIDER / MODELO
const provider = cfg('ai_provider', 'openai');
let model, temperature, max_tokens;
if (provider === 'claude') {
  model = cfg('claude_model', 'claude-haiku-4-5');
  temperature = parseFloat(cfg('claude_temperature', '0.7'));
  max_tokens = parseInt(cfg('claude_max_tokens', '1024'));
} else if (provider === 'google') {
  model = cfg('google_model', 'gemini-2.0-flash');
  temperature = parseFloat(cfg('google_temperature', '0.7'));
  max_tokens = parseInt(cfg('google_max_tokens', '1024'));
} else {
  model = cfg('openai_model', 'gpt-4o-mini');
  temperature = parseFloat(cfg('openai_temperature', '0.7'));
  max_tokens = parseInt(cfg('openai_max_tokens', '1024'));
}

// HISTÓRICO
const histRaw = $('Get History').first().json;
const history = Array.isArray(histRaw) ? histRaw : [];
const messages = [{ role: 'system', content: prompt }];
[...history].reverse().forEach(msg => {
  messages.push({ role: msg.sender === 'assistant' ? 'assistant' : 'user', content: msg.conteudo });
});
messages.push({ role: 'user', content: $('Parse Message').first().json.text });

return [{ json: {
  provider, model, temperature, max_tokens, messages,
  user_id: agentData.user_id,
  msg_qualificado: cfg('msg_qualificado', 'Parabéns! Você foi qualificado.'),
  msg_desqualificado: cfg('msg_desqualificado', 'Obrigado pelo contato!'),
  responder_em_audio: cfg('responder_em_audio', 'false'),
  numero_destino: cfg('numero_destino'),
  grupo_destino: cfg('grupo_destino'),
  notif_destino: configMap['notif_destino'] || 'numero'
} }];

// ========================================================
// PROCESS RESPONSE — Detecta qualificação, objeções, limpa tags
// ========================================================
const llm = $('LLM Call').first().json;
const response = llm.content || llm.choices?.[0]?.message?.content || '';
const promptData = $('Build Prompt').first().json;
const userText = ($('Parse Message').first().json.text || '').toLowerCase();
const agentData = $('Process Data').first().json;

const qualified = response.includes('[LEAD_QUALIFICADO]');
const disqualified = response.includes('[LEAD_DESQUALIFICADO]');
const payment = response.includes('[INICIAR_PAGAMENTO]');

const objWords = ['não posso','muito caro','não sei','concorrente','depois','não tenho','sem interesse','tá caro','está caro'];
let has_objection = false, objection_type = '';
for (const kw of objWords) {
  if (userText.includes(kw)) {
    has_objection = true;
    objection_type = kw.includes('caro') || kw.includes('não tenho') ? 'preco' : kw.includes('depois') ? 'timing' : kw.includes('concorrente') ? 'concorrente' : 'outro';
    break;
  }
}

let clean = response.replace(/\[LEAD_QUALIFICADO\]/g,'').replace(/\[LEAD_DESQUALIFICADO\]/g,'').replace(/\[INICIAR_PAGAMENTO\]/g,'').trim();

let new_stage = agentData.stage;
if (qualified) new_stage = 'qualificado';
else if (disqualified) new_stage = 'nao_qualificado';
else if (agentData.stage === 'novo_contato') new_stage = 'em_atendimento';

return [{ json: {
  response_text: clean, qualified, disqualified, payment_intent: payment,
  has_objection, objection_type, new_stage,
  tokens_used: llm.deducted_tokens || 0,
  numero_destino: promptData.numero_destino,
  notif_destino: promptData.notif_destino
} }];
